export const isHubspotExtensibilityImport = (importSource) => {
    return (typeof importSource === 'string' &&
        importSource.startsWith('@hubspot/ui-extensions'));
};
/**
 * Finds the local name of a specific imported component from an ImportDeclaration.
 *
 * This is useful for handling aliased imports, where the component is imported with a different name.
 *
 * For example:
 * import { Image as HubImage } from '@hubspot/ui-extensions';
 *
 * In this case, calling getImportedComponentName(node, 'Image') would return 'HubImage'.
 *
 * @param node - The ImportDeclaration AST node
 * @param componentName - The original name of the component being imported
 * @returns The local name of the imported component, or null if not found
 */
export const getImportedComponentName = (node, componentName) => {
    for (const specifier of node.specifiers) {
        if (specifier.type === 'ImportSpecifier' &&
            specifier.imported.type === 'Identifier' &&
            specifier.imported.name === componentName) {
            return specifier.local.name;
        }
    }
    return null;
};
/**
 * Checks if an import source is a relative import.
 *
 * Relative imports start with './' or '../' and are used to import
 * files relative to the current file's location.
 *
 * For example:
 * - './utils' → returns true
 * - '../shared/constants' → returns true
 * - '@hubspot/ui-extensions' → returns false
 * - 'react' → returns false
 *
 * @param importSource - The import source to check
 * @returns True if the import source is a relative import
 */
export const isRelativeImport = (importSource) => {
    return (typeof importSource === 'string' &&
        (importSource.startsWith('./') || importSource.startsWith('../')));
};
export const isExperimentalImport = (importSource) => {
    return (typeof importSource === 'string' &&
        isHubspotExtensibilityImport(importSource) &&
        importSource.includes('/experimental'));
};
